object ConfigXmlParser {

  private def createSecureSAXParser(): SAXParser = {
    val factory = SAXParserFactory.newInstance()
    factory.setNamespaceAware(false)
    factory.setValidating(false)
    // Disable external entities to prevent XXE attacks
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.newSAXParser()
  }

  def parseXml(xmlString: String): Either[String, Elem] = {
    Try {
      val parser = createSecureSAXParser()
      XML.withSAXParser(parser).loadString(xmlString)
    } match {
      case Success(elem) => Right(elem)
      case Failure(ex) => Left(s"XML parsing error: ${ex.getMessage}")
    }
  }

  def extractSettings(root: Elem): List[ConfigSetting] = {
    val settings = mutable.ListBuffer[ConfigSetting]()

    def extractFromNode(node: Node, currentSection: String): Unit = {
      node.label match {
        case "setting" | "property" | "param" =>
          val key = (node \ "@key").headOption
            .orElse((node \ "@name").headOption)
            .map(_.text)
            .getOrElse("")
          val value = (node \ "@value").headOption
            .map(_.text)
            .getOrElse(node.text.trim)
          if (key.nonEmpty) {
            settings += ConfigSetting(key, value, currentSection)
          }

        case "section" | "group" | "category" =>
          val sectionName = (node \ "@name").headOption
            .orElse((node \ "@id").headOption)
            .map(_.text)
            .getOrElse(node.label)
          val fullSection = if (currentSection.isEmpty) sectionName else s"$currentSection.$sectionName"
          node.child.foreach(child => extractFromNode(child, fullSection))

        case "entry" =>
          val key = (node \ "@key").headOption.map(_.text).getOrElse("")
          val value = node.text.trim
          if (key.nonEmpty) {
            settings += ConfigSetting(key, value, currentSection)
          }

        case "include" | "import" =>
          val ref = (node \ "@ref").headOption
            .orElse((node \ "@file").headOption)
            .map(_.text)
            .getOrElse("")
          if (ref.nonEmpty) {
            settings += ConfigSetting(s"__include__", ref, currentSection)
          }

        case _ =>
          // For generic elements, check if they contain text directly (leaf nodes with config values)
          if (node.child.exists(_.isInstanceOf[scala.xml.Text]) && node.child.length == 1) {
            val key = node.label
            val value = node.text.trim
            if (key.nonEmpty && value.nonEmpty && key != "#PCDATA") {
              settings += ConfigSetting(key, value, currentSection)
            }
          } else {
            val sectionName = if (currentSection.isEmpty) node.label else s"$currentSection.${node.label}"
            node.child.foreach(child => extractFromNode(child, sectionName))
          }
      }
    }

    root.child.foreach(child => extractFromNode(child, ""))
    settings.toList
  }

  def extractSections(root: Elem): List[String] = {
    val sections = mutable.LinkedHashSet[String]()

    def findSections(node: Node, prefix: String): Unit = {
      node.label match {
        case "section" | "group" | "category" =>
          val name = (node \ "@name").headOption
            .orElse((node \ "@id").headOption)
            .map(_.text)
            .getOrElse(node.label)
          val fullName = if (prefix.isEmpty) name else s"$prefix.$name"
          sections += fullName
          node.child.foreach(child => findSections(child, fullName))
        case label if label != "#PCDATA" && node.child.exists(!_.isInstanceOf[scala.xml.Text]) =>
          val fullName = if (prefix.isEmpty) label else s"$prefix.$label"
          if (node.child.count(c => !c.isInstanceOf[scala.xml.Text] && c.label != "#PCDATA") > 0) {
            sections += fullName
          }
          node.child.foreach(child => findSections(child, fullName))
        case _ =>
      }
    }

    root.child.foreach(child => findSections(child, ""))
    sections.toList
  }

  def resolveEntityReferences(settings: List[ConfigSetting]): List[ConfigSetting] = {
    val settingsMap = settings.map(s => s"${s.section}.${s.key}" -> s.value).toMap

    def resolveValue(value: String): String = {
      val pattern = """\$\{([^}]+)\}""".r
      var resolved = value
      var iterations = 0
      val maxIterations = 10

      while (pattern.findFirstIn(resolved).isDefined && iterations < maxIterations) {
        resolved = pattern.replaceAllIn(resolved, m => {
          val ref = m.group(1)
          val replacement = settingsMap.getOrElse(ref,
            settingsMap.getOrElse(s".$ref", m.matched)
          )
          java.util.regex.Matcher.quoteReplacement(replacement)
        })
        iterations += 1
      }
      resolved
    }

    settings.map(s => s.copy(value = resolveValue(s.value)))
  }
}

object ConfigManagementService {

  import JsonProtocol._

  private val configStore = mutable.Map[String, ParsedConfig]()

  def main(args: Array[String]): Unit = {
    implicit val system: ActorSystem = ActorSystem("config-management")
    import system.dispatcher

    val route: Route = concat(
      path("api" / "config" / "parse") {
        post {
          entity(as[ParseRequest]) { request =>
            val result = processXmlConfig(request.xml)
            complete(result)
          }
        }
      },
      path("api" / "config" / "parse" / "raw") {
        post {
          entity(as[String]) { xmlBody =>
            val result = processXmlConfig(xmlBody)
            import JsonProtocol._
            complete(HttpEntity(ContentTypes.`application/json`, result.toJson.compactPrint))
          }
        }
      },
      path("api" / "config" / "store" / Segment) { configId =>
        post {
          entity(as[ParseRequest]) { request =>
            val result = processXmlConfig(request.xml)
            result.config.foreach(c => configStore.put(configId, c))
            complete(result)
          }
        } ~
        get {
          configStore.get(configId) match {
            case Some(config) =>
              complete(ParseResponse(success = true, Some(config), None))
            case None =>
              complete(StatusCodes.NotFound -> ParseResponse(success = false, None, Some(s"Config '$configId' not found")))
          }
        } ~
        delete {
          configStore.remove(configId)
          complete(ParseResponse(success = true, None, None))
        }
      },
      path("api" / "config" / "store" / Segment / "setting") { configId =>
        parameters("section".optional, "key".optional) { (section, key) =>
          get {
            configStore.get(configId) match {
              case Some(config) =>
                val filtered = config.settings.filter { s =>
                  section.forall(sec => s.section == sec || s.section.startsWith(sec)) &&
                    key.forall(k => s.key == k)
                }
                complete(ParseResponse(success = true, Some(config.copy(settings = filtered)), None))
              case None =>
                complete(StatusCodes.NotFound -> ParseResponse(success = false, None, Some(s"Config '$configId' not found")))
            }
          }
        }
      },
      path("api" / "config" / "validate") {
        post {
          entity(as[ParseRequest]) { request =>
            ConfigXmlParser.parseXml(request.xml) match {
              case Right(_) =>
                complete(ParseResponse(success = true, None, None))
              case Left(error) =>
                complete(StatusCodes.BadRequest -> ParseResponse(success = false, None, Some(error)))
            }
          }
        }
      },
      path("api" / "config" / "list") {
        get {
          val ids = configStore.keys.toList
          complete(ids.toJson.compactPrint)
        }
      },
      path("health") {
        get {
          complete(StatusCodes.OK -> """{"status":"healthy"}""")
        }
      }
    )

    val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

    bindingFuture.foreach { binding =>
      println(s"Configuration Management Service running at http://${binding.localAddress.getHostString}:${binding.localAddress.getPort}/")
    }

    bindingFuture.failed.foreach { ex =>
      println(s"Failed to bind HTTP server: ${ex.getMessage}")
      system.terminate()
    }
  }

  private def processXmlConfig(xmlString: String): ParseResponse = {
    ConfigXmlParser.parseXml(xmlString) match {
      case Right(root) =>
        val rawSettings = ConfigXmlParser.extractSettings(root)
        val resolvedSettings = ConfigXmlParser.resolveEntityReferences(rawSettings)
        val sections = ConfigXmlParser.extractSections(root)
        val config = ParsedConfig(
          settings = resolvedSettings,
          sections = sections,
          raw = xmlString
        )
        ParseResponse(success = true, Some(config), None)

      case Left(error) =>
        ParseResponse(success = false, None, Some(error))
    }
  }
}